            String code = context.getTextSubstring(context.getIndex(), endPos);
            try {
                context.setCurrency(CurrencyUnit.of1(code));
                context.setIndex(endPos);
            } catch (IllegalCurrencyException ex) {
                context.setError();
            }
        }
    }
},
